"""IAF MCP Server v1.6.0 - WorkflowContext"""
import os,json,re,hashlib,requests,base64,time,sys,uuid
from fastmcp import FastMCP
from fastmcp.server.dependencies import get_http_request
try:import numpy as _np;_HAS_NP=True
except ImportError:_HAS_NP=False
if hasattr(sys.stdout,'reconfigure'):sys.stdout.reconfigure(encoding='utf-8',errors='replace')
if hasattr(sys.stderr,'reconfigure'):sys.stderr.reconfigure(encoding='utf-8',errors='replace')

mcp=FastMCP(name="IAF MCP Server")
BU=os.environ.get("IAF_BASE_URL","http://10.77.82.120:5001")
MS=os.environ.get("MODEL_SERVER_URL","http://100.78.161.12:5500")
_HOME=os.path.expanduser("~")
CF=os.path.join(_HOME,".iaf_credentials.json")  # Shared - login creds for this machine
EC=os.path.join(_HOME,".iaf_emb_cache.json")   # Shared - tool embeddings are same for all users

# User-specific files - computed dynamically based on JWT token
def _decode_jwt_payload(token):
    """Decode JWT payload to extract user info"""
    try:
        if token.startswith("Bearer "):token=token[7:]
        p=token.split(".")
        if len(p)!=3:return {}
        pad=p[1]+"="*(4-len(p[1])%4)
        return json.loads(base64.urlsafe_b64decode(pad))
    except:return {}

def _get_current_user_id():
    """Get user ID from current auth context for multi-user file isolation"""
    # Priority 1: env headers (set by API gateway)
    t=os.environ.get("access-token")
    if t:
        try:
            h=json.loads(t)
            if h.get("x-user-email"):return h["x-user-email"].split('@')[0].replace('.','_')
            if h.get("authorization"):return _decode_jwt_payload(h["authorization"]).get("mail_id","").split('@')[0].replace('.','_') or "default"
        except:pass
    # Priority 2: stored credentials
    if os.path.exists(CF):
        try:
            with open(CF) as f:c=json.load(f)
            if c.get('email'):return c['email'].split('@')[0].replace('.','_')
            if c.get('token'):return _decode_jwt_payload(c['token']).get("mail_id","").split('@')[0].replace('.','_') or "default"
        except:pass
    return "default"

def _user_file(base):
    """Get user-specific state file path: .iaf_kb_state.json -> .iaf_kb_state_sai_dharmala.json"""
    uid=_get_current_user_id()
    name,ext=os.path.splitext(base)
    return os.path.join(_HOME,f"{name}_{uid}{ext}")

# Dynamic user-specific paths
def _KF():return _user_file(".iaf_kb_state.json")   # KB pending selections
def _WF():return _user_file(".iaf_workflow.json")   # Workflow context

def _r(f,d):
    try:
        with open(f) as fp:return json.load(fp)
    except:return d
def _w(f,d):
    try:
        with open(f,'w') as fp:json.dump(d,fp)
    except:pass

def read_kb_state():kf=_KF();return _r(kf,{'ids':[],'names':{}}).get('ids',[]) if os.path.exists(kf) else []
def clear_kb_state():_w(_KF(),{'ids':[],'names':{}})
def save_creds(e,t):_w(CF,{"email":e,"token":t})
def load_creds():return _r(CF,{}) if os.path.exists(CF) else {}

# WorkflowContext - tracks tool IDs across agent creation session (user-specific)
def _wf_init():
    uid=_get_current_user_id()
    return {"sid":f"usr_{uid}_{uuid.uuid4().hex[:4]}","user":uid,"plan":{"caps":[],"total":0,"identified":0,"to_create":0},"discovered":{},"selected":{},"created":{},"step":"init"}
def _wf_load():
    wf=_WF()
    if os.path.exists(wf):return _r(wf,_wf_init())
    return _wf_init()
def _wf_save(w):_w(_WF(),w)
def _wf_reset():_w(_WF(),_wf_init())
def _wf_reg_discovered(name,tid):
    w=_wf_load();w["discovered"][name]=tid;_wf_save(w)
def _wf_reg_selected(name,tid):
    w=_wf_load();w["selected"][name]=tid;w["plan"]["identified"]=len(w["selected"]);_wf_save(w)
def _wf_reg_created(name,tid):
    w=_wf_load();w["created"][name]=tid;_wf_save(w)
def _wf_resolve(tools):
    """Resolve tool names to IDs using workflow context"""
    w=_wf_load();resolved=[];unresolved=[]
    for t in (tools if isinstance(tools,list) else [tools]):
        t=t.strip()
        if re.match(r'^[a-f0-9]{8}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{12}$',t,re.I):
            resolved.append(t)
        elif t in w["created"]:resolved.append(w["created"][t])
        elif t in w["selected"]:resolved.append(w["selected"][t])
        elif t in w["discovered"]:resolved.append(w["discovered"][t])
        else:unresolved.append(t)
    return resolved,unresolved
def _wf_status():
    w=_wf_load()
    return f"Session:{w['sid']}\nStep:{w['step']}\nSelected:{len(w['selected'])} Created:{len(w['created'])}\nTools: {list(w['selected'].keys())+list(w['created'].keys())}"
def get_token(e,pw):
    r=requests.post(f"{BU}/auth/login",json={"email_id":e,"password":pw})
    return r.json().get('token') if r.status_code==200 else None

def _env_headers():
    t=os.environ.get("access-token")
    if t:
        try:return json.loads(t)
        except:pass
    return {}

def _decode_jwt(token):
    """Alias for backward compatibility"""
    return _decode_jwt_payload(token)

def auth():
    h=_env_headers()
    if h:
        ah=h.get("authorization","")
        if ah.startswith("Bearer "):return True,ah
        if ah:return True,f"Bearer {ah}"
    c=load_creds()
    if c.get('token'):return True,f"Bearer {c['token']}"
    return False,"[AUTH] Not authenticated. Pass Authorization header or call iaf_login."

def get_email():
    h=_env_headers()
    if h:
        e=h.get("x-user-email")
        if e:return e
        ah=h.get("authorization","")
        if ah:
            cl=_decode_jwt(ah)
            if cl.get("mail_id"):return cl["mail_id"]
    try:
        req=get_http_request()
        if req:
            e=req.headers.get("x-user-email","")
            if e:return e
    except:pass
    return load_creds().get('email','mcp@iaf.com')

def get_embeddings(texts):
    try:
        r=requests.post(f"{MS}/embeddings",json={"texts":texts,"model":"all-MiniLM-L6-v2"},timeout=30)
        if r.status_code==200:return r.json().get('embeddings',[])
    except:pass
    return []

def cosine_sim(v1,v2):
    if not v1 or not v2:return 0.0
    d=sum(a*b for a,b in zip(v1,v2))
    m1=sum(a*a for a in v1)**0.5;m2=sum(b*b for b in v2)**0.5
    return d/(m1*m2) if m1 and m2 else 0.0

def _batch_cosine(query_vec,emb_cache,ids):
    ids=[i for i in ids if i in emb_cache]
    if not ids:return {}
    if _HAS_NP:
        M=_np.array([emb_cache[i] for i in ids],dtype=_np.float32)
        q=_np.array(query_vec,dtype=_np.float32)
        rn=_np.linalg.norm(M,axis=1);rn[rn==0]=1.0
        qn=_np.linalg.norm(q)
        if qn==0:return {i:0.0 for i in ids}
        sims=(M/rn[:,None])@(q/qn)
        return dict(zip(ids,sims.tolist()))
    return {i:cosine_sim(query_vec,emb_cache[i]) for i in ids}

def _normalize_name(n):
    n=re.sub(r'([a-z])([A-Z])',r'\1 \2',n)
    n=re.sub(r'([A-Z]+)([A-Z][a-z])',r'\1 \2',n)
    return n.replace('_',' ').replace('-',' ').lower()

def _desc_hash(t):
    return hashlib.md5(f"v2|{_normalize_name(t.get('tool_name',''))}|{t.get('tool_description','')}".encode()).hexdigest()

def get_cached_embeddings(tools):
    t0=time.time();total=len(tools);live_ids={t.get('tool_id') for t in tools}
    ex=os.path.exists(EC);cache=_r(EC,{"e":{},"h":{}}) if ex else {"e":{},"h":{}}
    ce,ch=cache["e"],cache["h"]
    print(f"[CACHE] {'Loaded' if ex else 'Empty'} {len(ce)} cached ({(time.time()-t0)*1000:.0f}ms)")
    deleted=[tid for tid in list(ce.keys()) if tid not in live_ids]
    if deleted:
        for tid in deleted:ce.pop(tid,None);ch.pop(tid,None)
        print(f"[CACHE] Evicted {len(deleted)} deleted")
    t1=time.time()
    to_embed=[(t,_desc_hash(t)) for t in tools if t.get('tool_id') not in ce or ch.get(t.get('tool_id'))!=_desc_hash(t)]
    print(f"[CACHE] {total-len(to_embed)}/{total} hits, {len(to_embed)} to embed ({(time.time()-t1)*1000:.0f}ms)")
    if to_embed:
        t2=time.time()
        names=[t.get('tool_name','?') for t,_ in to_embed]
        print(f"[CACHE] Embedding {len(to_embed)}: {names[:5]}{'...' if len(names)>5 else ''}")
        texts=[f"{_normalize_name(t.get('tool_name',''))} {t.get('tool_description','')}" for t,_ in to_embed]
        embs=get_embeddings(texts)
        if embs and len(embs)==len(to_embed):
            for i,(t,h) in enumerate(to_embed):ce[t['tool_id']]=embs[i];ch[t['tool_id']]=h
            _w(EC,{"e":ce,"h":ch})
            print(f"[CACHE] Saved {len(to_embed)} embeddings ({(time.time()-t2)*1000:.0f}ms)")
        else:
            print(f"[CACHE] WARNING: got {len(embs)} vectors for {len(to_embed)} tools")
    elif deleted:
        _w(EC,{"e":ce,"h":ch});print("[CACHE] Saved after eviction")
    else:
        print(f"[CACHE] FULL HIT - all {total} from disk")
    print(f"[CACHE] Done {(time.time()-t0)*1000:.0f}ms");return ce

def _kw_search(query,tools,n):
    qs=set(query.lower().split());sc=[]
    for t in tools:
        nm=_normalize_name(t.get('tool_name',''));tx=nm+" "+t.get('tool_description','').lower()
        s=sum(1+int(w in nm) for w in qs if len(w)>2 and w in tx)
        if s:sc.append((t,s))
    sc.sort(key=lambda x:-x[1]);top=sc[:n]
    if not top:return f"No tools match '{query}'"
    return "\n".join([f"{i+1}. {t['tool_name']} (ID:{t['tool_id']})\n   {t.get('tool_description','')[:150]}" for i,(t,_) in enumerate(top)])

@mcp.tool()
def iaf_login(email:str,password:str)->str:
    """Login to IAF (fallback when HTTP auth headers unavailable)"""
    t=get_token(email,password)
    if t:save_creds(email,t);return f"[OK] Logged in as {email}"
    return "[FAILED] Invalid credentials"

@mcp.tool()
def iaf_get_tools()->str:
    """List all available tools"""
    ok,tk=auth()
    if not ok:return tk
    try:
        r=requests.get(f"{BU}/tools/get",headers={"Authorization":tk})
        if r.status_code==200:
            ts=r.json()
            if not ts:return "No tools"
            return "\n".join([f"{t['tool_name']} ({t['tool_id']}): {t.get('tool_description','')[:100]}" for t in ts])
        return f"[FAILED] {r.text}"
    except Exception as e:return f"[ERROR] {e}"

@mcp.tool()
def iaf_suggest_tools(query:str,max_results:int=8)->str:
    """Semantic tool search. Falls back to keyword search if embedding server unavailable."""
    ok,tk=auth()
    if not ok:return tk
    try:
        r=requests.get(f"{BU}/tools/get",headers={"Authorization":tk},timeout=10)
        if r.status_code!=200:return f"[FAILED] {r.text}"
        tools=r.json()
        if not tools:return "No tools"
        ce=get_cached_embeddings(tools)
        if not ce:return _kw_search(query,tools,max_results)
        qe=get_embeddings([query])
        if not qe:return _kw_search(query,tools,max_results)
        sim_map=_batch_cosine(qe[0],ce,[t['tool_id'] for t in tools])
        sims=sorted([(t,sim_map[t['tool_id']]) for t in tools if t['tool_id'] in sim_map],key=lambda x:-x[1])
        top=sims[:max_results]
        if not top:return f"No tools match '{query}'"
        res=f"Tools for '{query}':\n"
        for i,(t,s) in enumerate(top):
            lbl="[HIGH]" if s>0.7 else "[MED]" if s>0.4 else "[LOW]"
            res+=f"{i+1}. {t['tool_name']} {lbl}({s:.2f}) ID:{t['tool_id']}\n   {t.get('tool_description','')[:150]}\n"
            _wf_reg_discovered(t['tool_name'],t['tool_id'])  # Register in workflow
        return res+f"\nIDs: {[t[0]['tool_id'] for t in top]}"
    except Exception as e:return f"[ERROR] {e}"

