@mcp.tool()
def iaf_create_tool(tool_description:str,code_snippet:str,model_name:str="gpt-4o")->str:
    """Create tool. Code MUST have type hints on all args and return type. Example: def add(a:int,b:int)->str:"""
    ok,tk=auth()
    if not ok:return tk
    # Normalize escaped sequences from LLM output
    cs=code_snippet.replace('\\\\n','\n').replace('\\n','\n').replace('\\t','\t')
    cs=cs.replace("\\'","'").replace('\\"','"')
    # Fix single-line code: add newlines after key patterns
    if cs.count('\n')<3 and 'def ' in cs:
        cs=re.sub(r':\s*"""',': \n    """',cs)
        cs=re.sub(r'"""\s*(?=[a-zA-Z])','\'\'\'\n    ',cs)
        cs=re.sub(r'\]\s*(?=[a-zA-Z])',']\n    ',cs)
        cs=re.sub(r'\)\s*(?=return\b)',')\n    ',cs)
    m=re.search(r'def\s+\w+\(([^)]*)',cs)
    if m and m.group(1).strip() and ':' not in m.group(1):
        return "[ERROR] Code MUST have type hints on all args. Example: def fn(x:str)->str:"
    if '->' not in cs:
        return "[ERROR] Code MUST have a return type hint. Example: def fn(x:str)->str:"
    try:
        r=requests.post(f"{BU}/tools/add?force_add=true",headers={"Authorization":tk,"Content-Type":"application/json"},json={"tool_description":tool_description,"code_snippet":cs,"model_name":model_name,"created_by":get_email()})
        if r.status_code==200:
            d=r.json()
            # API may wrap result or return fields directly
            res=d.get('result',d)
            tid=res.get('tool_id') or d.get('tool_id','')
            tname=res.get('tool_name') or d.get('tool_name','')
            fn=re.search(r'def\s+(\w+)',cs)
            tname=tname or (fn.group(1) if fn else 'unknown')
            _wf_reg_created(tname,tid)  # Register in workflow
            return f"[OK] Tool '{tname}' ID:{tid}"
        err=r.text
        if 'already exists' in err.lower():
            fn=re.search(r'def\s+(\w+)',cs)
            return f"[FAILED] Tool '{fn.group(1) if fn else 'unknown'}' already exists. Use iaf_suggest_tools."
        return f"[FAILED] {err}"
    except Exception as e:return f"[ERROR] {e}"

VALID_AGENT_TYPES=['react_agent','react_critic_agent','planner_executor_agent','planner_executor_critic_agent','meta_agent','hybrid_agent','planner_meta_agent']

@mcp.tool()
def iaf_create_agent(agent_name:str,agent_goal:str,workflow_description:str,tools_id:list,agent_type:str="react_agent",model_name:str="gpt-4o",knowledgebase_ids:list=None)->str:
    """Create agent with tools and optional KB. agent_type: react_agent, react_critic_agent, planner_executor_agent, planner_executor_critic_agent, meta_agent, hybrid_agent, planner_meta_agent"""
    if agent_type not in VALID_AGENT_TYPES:
        return f"[ERROR] Invalid agent_type '{agent_type}'. Valid: {', '.join(VALID_AGENT_TYPES)}"
    ok,tk=auth()
    if not ok:return tk
    # Auto-resolve tool names to IDs using workflow context
    resolved,unresolved=_wf_resolve(tools_id)
    if unresolved:
        # Try semantic search for unresolved names
        for name in unresolved:
            try:
                r=requests.get(f"{BU}/tools/get",headers={"Authorization":tk},timeout=10)
                if r.status_code==200:
                    for t in r.json():
                        if t.get('tool_name','').lower()==name.lower():
                            resolved.append(t['tool_id']);_wf_reg_selected(name,t['tool_id']);break
                    else:return f"[ERROR] Could not resolve tool '{name}'. Use iaf_suggest_tools to find it."
            except:return f"[ERROR] Could not resolve tool '{name}'"
    try:
        kb=knowledgebase_ids if knowledgebase_ids else read_kb_state()
        payload={"agent_name":agent_name,"agent_goal":agent_goal,"workflow_description":workflow_description,"agent_type":agent_type,"model_name":model_name,"tools_id":resolved,"email_id":get_email()}
        if kb:payload["knowledgebase_ids"]=kb if isinstance(kb,list) else [kb]
        r=requests.post(f"{BU}/agents/onboard",headers={"Authorization":tk,"Content-Type":"application/json"},json=payload)
        if r.status_code==200:
            d=r.json().get('result',{})
            aid=d.get('agent_id') or d.get('agentic_application_id')
            if kb:clear_kb_state()
            _wf_reset()  # Reset workflow after successful agent creation
            return f"[OK] Agent {agent_name} ({aid}){f', KBs: {len(kb)}' if kb else ''}"
        return f"[FAILED] {r.text}"
    except Exception as e:return f"[ERROR] {e}"

