from fastmcp import FastMCP
import sqlite3
from datetime import datetime, timedelta

mcp = FastMCP(name="Customer Analytics Server")

@mcp.tool()
def get_customer_profile(customer_id: str) -> str:
    """
    Retrieves comprehensive customer profile including account details and recent transactions.

    Args:
        customer_id: The unique identifier of the customer.

    Returns:
        Customer profile with account info and transaction summary.
    """
    try:
        conn = sqlite3.connect('user_uploads/customer_loyalty_agent_database.db')
        cursor = conn.cursor()

        cursor.execute('SELECT * FROM Customers WHERE customer_id = ?', (customer_id,))
        customer = cursor.fetchone()

        if not customer:
            conn.close()
            return f'Customer {customer_id} not found.'

        end_date = datetime.now()
        start_date = end_date - timedelta(days=90)

        cursor.execute(
            'SELECT COUNT(*), SUM(amount) FROM Transactions WHERE customer_id = ? AND transaction_date BETWEEN ? AND ?',
            (customer_id, start_date.strftime('%Y-%m-%d'), end_date.strftime('%Y-%m-%d'))
        )
        txn_stats = cursor.fetchone()
        conn.close()

        return f"""Customer Profile:
ID: {customer[0]}
Name: {customer[1]}
Email: {customer[2]}
Phone: {customer[3]}
Account Since: {customer[4]}
Card Limit: ${customer[5]}

Last 90 Days Activity:
Transactions: {txn_stats[0] or 0}
Total Spending: ${txn_stats[1] or 0:.2f}"""
    except Exception as e:
        return f'Error retrieving customer profile: {str(e)}'

@mcp.tool()
def calculate_loyalty_score(customer_id: str) -> str:
    """
    Calculates customer loyalty score based on account age, transaction frequency, and spending.

    Args:
        customer_id: The customer ID to calculate loyalty score for.

    Returns:
        Loyalty score assessment (High/Moderate/Low) with explanation.
    """
    try:
        conn = sqlite3.connect('user_uploads/customer_loyalty_agent_database.db')
        cursor = conn.cursor()

        cursor.execute('SELECT account_opening_date, card_limit FROM Customers WHERE customer_id = ?', (customer_id,))
        customer = cursor.fetchone()

        if not customer:
            conn.close()
            return f'Customer {customer_id} not found.'

        account_date = datetime.strptime(customer[0], '%Y-%m-%d')
        card_limit = customer[1]
        account_age_days = (datetime.now() - account_date).days

        end_date = datetime.now()
        start_date = end_date - timedelta(days=90)

        cursor.execute(
            'SELECT COUNT(*), SUM(amount) FROM Transactions WHERE customer_id = ? AND transaction_date BETWEEN ? AND ?',
            (customer_id, start_date.strftime('%Y-%m-%d'), end_date.strftime('%Y-%m-%d'))
        )
        txn_count, total_spending = cursor.fetchone()
        txn_count = txn_count or 0
        total_spending = total_spending or 0
        conn.close()

        score = 0
        reasons = []

        if account_age_days > 3 * 365:
            score += 1
            reasons.append('Long-term customer (3+ years)')
        if txn_count > 10:
            score += 1
            reasons.append('Frequent transactions (10+ in 90 days)')
        if total_spending > card_limit / 4:
            score += 1
            reasons.append('High spending (>25% of card limit)')

        loyalty = 'High' if score >= 3 else ('Moderate' if score >= 2 else 'Low')

        return f"""Loyalty Assessment for Customer {customer_id}:
Score: {loyalty}
Factors:
- Account Age: {account_age_days} days
- Recent Transactions: {txn_count}
- Recent Spending: ${total_spending:.2f}

Reasoning: {', '.join(reasons) if reasons else 'New or low-activity customer'}"""
    except Exception as e:
        return f'Error calculating loyalty: {str(e)}'

