"""IAF KB MCP Server"""
from fastmcp import FastMCP
from fastmcp.server.dependencies import get_http_request
import requests,os,json,base64
mcp=FastMCP(name="IAF KB Server")
_HOME=os.path.expanduser("~")
CF=os.path.join(_HOME,".iaf_credentials.json")  # Shared credentials
BU=os.environ.get("IAF_BASE_URL","http://10.77.82.120:5001")

# User-specific file path helpers
def _decode_jwt_payload(token):
    """Decode JWT payload to extract user info"""
    try:
        if token.startswith("Bearer "):token=token[7:]
        p=token.split(".")
        if len(p)!=3:return {}
        pad=p[1]+"="*(4-len(p[1])%4)
        return json.loads(base64.urlsafe_b64decode(pad))
    except:return {}

def _get_current_user_id():
    """Get user ID from current auth context for multi-user file isolation"""
    t=os.environ.get("access-token")
    if t:
        try:
            h=json.loads(t)
            if h.get("x-user-email"):return h["x-user-email"].split('@')[0].replace('.','_')
            if h.get("authorization"):return _decode_jwt_payload(h["authorization"]).get("mail_id","").split('@')[0].replace('.','_') or "default"
        except:pass
    if os.path.exists(CF):
        try:
            with open(CF) as f:c=json.load(f)
            if c.get('email'):return c['email'].split('@')[0].replace('.','_')
            if c.get('token'):return _decode_jwt_payload(c['token']).get("mail_id","").split('@')[0].replace('.','_') or "default"
        except:pass
    return "default"

def _user_file(base):
    """Get user-specific state file: .iaf_kb_state.json -> .iaf_kb_state_sai_dharmala.json"""
    uid=_get_current_user_id()
    name,ext=os.path.splitext(base)
    return os.path.join(_HOME,f"{name}_{uid}{ext}")

def _KF():return _user_file(".iaf_kb_state.json")

def load_creds():
    if os.path.exists(CF):
        try:
            with open(CF,'r') as f:return json.load(f)
        except:pass
    return {}

def _env_headers():
    t=os.environ.get("access-token")
    if t:
        try:return json.loads(t)
        except:pass
    return {}

def _decode_jwt(token):
    """Alias for backward compatibility"""
    return _decode_jwt_payload(token)

def auth():
    """Auth priority: env headers > HTTP Authorization header > stored creds from iaf_login"""
    h=_env_headers()
    if h:
        ah=h.get("authorization","")
        if ah.startswith("Bearer "):return True,ah
        if ah:return True,f"Bearer {ah}"
    try:
        req=get_http_request()
        if req:
            ah=req.headers.get("authorization","")
            if ah.startswith("Bearer "):return True,ah
            if ah:return True,f"Bearer {ah}"
    except:pass
    c=load_creds()
    if c.get('token'):return True,f"Bearer {c['token']}"
    return False,"[AUTH] Not authenticated. Pass Authorization header or call iaf_login in the main MCP server."

def get_email():
    h=_env_headers()
    if h:
        e=h.get("x-user-email")
        if e:return e
        ah=h.get("authorization","")
        if ah:
            cl=_decode_jwt(ah)
            if cl.get("mail_id"):return cl["mail_id"]
    try:
        req=get_http_request()
        if req:
            e=req.headers.get("x-user-email","")
            if e:return e
    except:pass
    return load_creds().get('email','mcp@iaf.com')

def load_kb_state():
    kf=_KF()
    default={"ids":[],"names":{}}
    if os.path.exists(kf):
        try:
            with open(kf,'r') as f:
                s=json.load(f)
            # Migrate old format - ensure all keys exist
            if "names" not in s:s["names"]={}
            if "ids" not in s:s["ids"]=[]
            return s
        except:pass
    return default

def save_kb_state(s):
    with open(_KF(),'w') as f:json.dump(s,f)

def add_kb(kid,name=None):
    s=load_kb_state()
    if kid not in s["ids"]:s["ids"].append(kid)
    if name:s["names"][kid]=name
    save_kb_state(s);return s["ids"]

def clear_kbs():save_kb_state({"ids":[],"names":{}})
def get_kbs():return load_kb_state()

@mcp.tool()
def iaf_kb_list()->str:
    """List all knowledge bases"""
    ok,tk=auth()
    if not ok:return tk
    try:
        r=requests.get(f"{BU}/utility/knowledge-base/list",headers={"Authorization":tk})
        if r.status_code==200:
            kbs=r.json().get("knowledge_bases",[])
            if not kbs:return "No KBs found"
            res=f"Found {len(kbs)} KB(s):\n"
            for kb in kbs:
                docs=kb.get('list_of_documents',[])
                res+=f"\n• {kb.get('kb_name')} ({kb.get('kb_id')})\n  Docs:{len(docs) if docs else 0} | {'Public' if kb.get('is_public') else 'Private'}\n"
            s=get_kbs()
            if s["ids"]:res+=f"\n[Pending: {len(s['ids'])} KB(s)]"
            return res
        return f"[FAILED] {r.text}"
    except Exception as e:return f"[ERROR] {e}"

@mcp.tool()
def iaf_kb_create(kb_name:str,file_paths:list,is_public:bool=True)->str:
    """Create KB from files. Auto-selects for binding - do NOT call iaf_kb_select after this."""
    ok,tk=auth()
    if not ok:return tk
    if not kb_name or not file_paths:return "[ERROR] kb_name and file_paths required"
    try:
        files=[];missing=[]
        for fp in file_paths:
            if os.path.exists(fp):files.append(('files',(os.path.basename(fp),open(fp,'rb'))))
            else:missing.append(fp)
        if missing:
            for _,(_, f) in files:f.close()
            return f"[ERROR] Files not found: {missing}"
        r=requests.post(f"{BU}/utility/knowledge-base/documents/upload",headers={"Authorization":tk},data={'session_id':'mcp','kb_name':kb_name,'user_email':get_email(),'is_public':'true' if is_public else 'false'},files=files)
        for _,(_, f) in files:f.close()
        if r.status_code==200:
            d=r.json();kid=d.get('kb_id')
            if kid:pending=add_kb(kid,kb_name)
            return f"[OK] KB '{kb_name}' ({kid}) created. {len(pending)} pending."
        return f"[FAILED] {r.text}"
    except Exception as e:return f"[ERROR] {e}"

@mcp.tool()
def iaf_kb_select(kb_id:str)->str:
    """Select existing KB for agent binding"""
    ok,tk=auth()
    if not ok:return tk
    if not kb_id:return "[ERROR] kb_id required"
    try:
        r=requests.get(f"{BU}/utility/knowledge-base/get/{kb_id}",headers={"Authorization":tk})
        if r.status_code==200:
            data=r.json()
            # API returns flat structure: {kb_id, kb_name, ...} not wrapped in 'knowledge_base'
            kb_name=data.get('kb_name') or data.get('name') or 'Unknown'
            pending=add_kb(kb_id,kb_name)
            return f"[OK] Selected '{kb_name}'. {len(pending)} pending."
        return f"[FAILED] KB not found"
    except Exception as e:return f"[ERROR] {e}"

