    ok,tk=auth()
    if not ok:return tk
    if not kb_id or not query:return "[ERROR] kb_id and query required"
    try:
        r=requests.post(f"{BU}/utility/knowledge-base/search",headers={"Authorization":tk,"Content-Type":"application/json"},json={"kb_id":kb_id,"query":query,"top_k":5})
