@mcp.tool()
def iaf_kb_delete(kb_ids:list)->str:
    """Delete KBs"""
    ok,tk=auth()
    if not ok:return tk
    if not kb_ids:return "[ERROR] kb_ids required"
    try:
        r=requests.delete(f"{BU}/utility/remove-knowledgebases",headers={"Authorization":tk,"Content-Type":"application/json"},json={"kb_ids":kb_ids,"user_email":get_email()})
